recommended_helpers.snippet_canonico:
async _publicarEvento(eventName, payload, sourcePayload = null) {
  if (!this.eventBus) {
    this.logger.warn(`${this.name}.event.bus_unavailable`, { event: eventName });
    return;
  }
  // Auto-extraer correlation_id: prioridad sourcePayload > payload.correlation_id > null
  const correlation_id =
    sourcePayload?.correlation_id ||
    payload?.correlation_id ||
    null;
  const finalPayload = {
    ...(correlation_id ? { correlation_id } : {}),
    ...payload,
    timestamp: payload.timestamp || new Date().toISOString()
  };
  try {
    await this.eventBus.publish(eventName, finalPayload);
    this.logger.info(`${this.name}.event.published`, {
      event: eventName,
      correlation_id
    });
  } catch (err) {
    this.logger.error(`${this.name}.event.publish.failed`, {
      event: eventName,
      error_message: err.message,
      stack: err.stack,
      correlation_id
    });
    this.metrics?.increment(`${this.name}.event.errors`, 1, { event: eventName });
  }
}

